import { Signal, scalar } from './signal';
import { Module } from './module';
import { MIDDLE_C_FREQ, P_TEMPO, SAMPLE_RATE, SAMPLE_RATE_RECIP, TAU } from './constants';
import * as env from './env';
import * as glide from './glide';
import * as effects from './effects';
import { ladder } from './ladder';
import { clamp, interpolatedRead } from './helpers';
import { Synth } from './synth';

export const msynthLib: Record<string, Module<any>> = {
  // ----- oscillators -----

  sine: Module.make({ input: () => scalar(440) }, params => {
    const f = params.input;
    let phase = 0;
    return Signal.new(() => {
      const sample = Math.sin(phase * TAU);
      const phaseInc = f.value * SAMPLE_RATE_RECIP;
      phase += phaseInc;
      phase -= Math.floor(phase);
      return sample;
    });
  }),

  saw: Module.make({ input: () => scalar(440) }, params => {
    const f = params.input;
    let phase = 0;
    return Signal.new(() => {
      const naiveSample = 2 * phase - 1;
      const phaseInc = f.value * SAMPLE_RATE_RECIP;
      const sample = naiveSample - polyBlep(phase, phaseInc);
      phase += phaseInc;
      phase -= Math.floor(phase);
      return sample;
    });
  }),

  tri: Module.make({ input: () => scalar(440) }, params => {
    const f = params.input;
    let phase = 0;
    let integrator = 0;
    return Signal.new(() => {
      const phaseInc = f.value * SAMPLE_RATE_RECIP;
      const square =
        (phase >= 0.25 && phase < 0.75 ? -1.0 : 1.0) -
        polyBlep((phase + 0.75) % 1, phaseInc) +
        polyBlep((phase + 0.25) % 1, phaseInc);
      integrator = 0.999 * integrator + square * phaseInc * 4;
      phase += phaseInc;
      phase -= Math.floor(phase);
      return integrator;
    });
  }),

  pulse: Module.make(
    { input: () => scalar(440), w: () => scalar(0.5), sync: () => scalar(0) },
    params => {
      const { input: f, w, sync } = params;
      let phase = 0;
      let prevSyncValue = 0;
      return Signal.new(() => {
        const naiveSample = phase < w.value ? -1 : 1;
        const phaseInc = f.value * SAMPLE_RATE_RECIP;
        const sample =
          naiveSample - polyBlep(phase, phaseInc) + polyBlep((phase - w.value + 1) % 1, phaseInc);

        let syncDetected = false;
        if (prevSyncValue < 0 && sync.value >= 0) {
          // estimate zero crossing between previous and current value
          // prev + (curr - prev) * r = 0  =>  r = -prev / (curr - prev)
          const r = -prevSyncValue / (sync.value - prevSyncValue);
          // time since crossing to current sample = (1 - r) * dt
          phase = Math.floor((1 - r) * phaseInc);
          syncDetected = true;
        }
        prevSyncValue = sync.value;

        if (!syncDetected) {
          phase += phaseInc;
          phase -= Math.floor(phase);
        }
        return sample;
      });
    }
  ),

  sampler: Module.make(
    {
      input: () => scalar(0),
      in: () => scalar(0),
      out: () => scalar(1),
      loopIn: () => scalar(0),
      loopOut: () => scalar(1),
    },
    params => {
      const { input: f, in: __in, out: _out, loopIn: _loopIn, loopOut: _loopOut } = params;
      let phase = 0;
      let stage: 'off' | 'on' | 'on-loop' = 'off';
      let sustain = false;

      function crossed(threshold: number, oldValue: number, newValue: number, direction: 1 | -1) {
        if (direction === 1) {
          return oldValue < threshold && threshold <= newValue;
        } else {
          return newValue < threshold && threshold <= oldValue;
        }
      }

      return Signal.new({
        nextSample(synth) {
          if (
            synth.numSamples === 0 || // samples haven't loaded yet
            stage === 'off'
          ) {
            phase = -1;
            return 0;
          }

          const _in = clamp(__in.value, 0, 1);
          const out = clamp(_out.value, 0, 1);
          const loopIn = clamp(_loopIn.value, 0, 1);
          const loopOut = clamp(_loopOut.value, 0, 1);

          const dir = stage === 'on' ? (out >= _in ? 1 : -1) : loopOut >= loopIn ? 1 : -1;
          const loopingMakesSense = dir > 0 ? loopIn < loopOut : loopIn > loopOut;

          const sample = interpolatedRead(synth.samples, phase * synth.numSamples);
          const oldPhase = phase;
          phase = clamp(phase + dir * (f.value / MIDDLE_C_FREQ / synth.numSamples), 0, 1);
          if (crossed(out, oldPhase, phase, dir)) {
            // if we hit "out", we're done
            phase = -1;
            stage = 'off';
          } else if (sustain && loopingMakesSense && crossed(loopOut, oldPhase, phase, dir)) {
            // when we hit loopOut, we're looping (jump back to loopIn)
            phase = loopIn;
            stage = 'on-loop';
          }
          return sample;
        },

        initialValue: 0,

        noteOn() {
          stage = 'on';
          phase = __in.value;
          sustain = true;
        },

        noteOff() {
          sustain = false;
        },

        writeSharedState(synth: Synth) {
          synth.addSamplerState(phase, __in.value, _out.value, _loopIn.value, _loopOut.value);
        },
      });
    }
  ),

  // ----- glides -----

  // TODO: consider adding lag(s: Signal, t: Signal) -- lag processor

  /** glide linearly (t is time for the signal to move 1 unit) */
  lglide: Module.make({ input: () => scalar(0), t: () => scalar(0.1) }, params =>
    glide.linear(params.input, params.t)
  ),

  /** glide exponentially (t is time for the signal to move 1 octave, in seconds) */
  eglide: Module.make({ input: () => scalar(0), t: () => scalar(1) }, params =>
    glide.exponential(params.input, params.t, false)
  ),

  legato: Module.make({ input: () => scalar(0), t: () => scalar(1) }, params =>
    glide.exponential(params.input, params.t, true)
  ),

  // ----- envelopes -----

  // TODO: in the 2600, the vca has a linear/exponential switch.
  // look at that and think about it -- maybe there are better building blocks for us?

  // TODO: consider taking an input param, whose default value is 1
  // (this would enable ad, adsr, etc. to be used in a pipeline kind of way, w/o multiplying by the input)

  ad: Module.make({ input: () => scalar(1), a: () => scalar(0), d: () => scalar(0.2) }, params =>
    env.ad(params.input, params.a, params.d)
  ),

  adsr: Module.make(
    {
      input: () => scalar(1),
      a: () => scalar(0),
      d: () => scalar(0),
      s: () => scalar(1),
      r: () => scalar(0.2),
    },
    params => env.adsr(params.input, params.a, params.d, params.s, params.r)
  ),

  gate: Module.make({ input: () => scalar(1) }, params => env.gate(params.input)),

  env: Module.make(
    {
      input: () => scalar(0),
      attackTime: () => scalar(0.001),
      releaseTime: () => scalar(0.05),
      filterFreq: () => scalar(1000),
      threshold: () => scalar(0.05),
    },
    params => {
      const { input, attackTime, releaseTime, filterFreq, threshold: _threshold } = params;
      let currentEnvelope = 0;
      let prevInput = 0;
      return Signal.new(() => {
        const attackCoef = Math.exp(-1.0 / (SAMPLE_RATE * attackTime.value));
        const releaseCoef = Math.exp(-1.0 / (SAMPLE_RATE * releaseTime.value));
        const filterCoef = 1.0 / (SAMPLE_RATE * filterFreq.value + 1.0);
        const threshold = _threshold.value;

        // 1. Pre-filter (Low-pass)
        const filteredInput = prevInput + attackCoef * (input.value - prevInput);
        prevInput = filteredInput;

        // 2. Full-wave rectification
        let rectified = Math.abs(filteredInput);

        // 3. Apply Threshold -- if the signal is below the threshold, it's ignored
        if (rectified < threshold) {
          rectified = 0;
        } else {
          rectified = (rectified - threshold) / (1.0 - threshold);
        }

        // 4. Smooth Envelope (Attack/Release)
        if (rectified > currentEnvelope) {
          currentEnvelope = rectified + attackCoef * (currentEnvelope - rectified);
        } else {
          currentEnvelope = rectified + releaseCoef * (currentEnvelope - rectified);
        }

        return Math.min(Math.max(currentEnvelope, 0), 1);
      });
    }
  ),

  // ----- filters -----

  lpf: Module.make(
    { input: () => scalar(0), cf: () => scalar(1000), q: () => scalar(0.2) },
    params => ladder('lp24', params.input, params.cf, params.q)
  ),

  lpf12: Module.make(
    { input: () => scalar(0), cf: () => scalar(1000), q: () => scalar(0.2) },
    params => ladder('lp12', params.input, params.cf, params.q)
  ),

  lpf24: Module.make(
    { input: () => scalar(0), cf: () => scalar(1000), q: () => scalar(0.2) },
    params => ladder('lp24', params.input, params.cf, params.q)
  ),

  hpf: Module.make(
    { input: () => scalar(0), cf: () => scalar(1000), q: () => scalar(0.2) },
    params => ladder('hp24', params.input, params.cf, params.q)
  ),

  hpf12: Module.make(
    { input: () => scalar(0), cf: () => scalar(1000), q: () => scalar(0.2) },
    params => ladder('hp12', params.input, params.cf, params.q)
  ),

  hpf24: Module.make(
    { input: () => scalar(0), cf: () => scalar(1000), q: () => scalar(0.2) },
    params => ladder('hp24', params.input, params.cf, params.q)
  ),

  bpf: Module.make(
    { input: () => scalar(0), cf: () => scalar(1000), q: () => scalar(0.2) },
    params => ladder('bp24', params.input, params.cf, params.q)
  ),

  bpf12: Module.make(
    { input: () => scalar(0), cf: () => scalar(1000), q: () => scalar(0.2) },
    params => ladder('bp12', params.input, params.cf, params.q)
  ),

  bpf24: Module.make(
    { input: () => scalar(0), cf: () => scalar(1000), q: () => scalar(0.2) },
    params => ladder('bp24', params.input, params.cf, params.q)
  ),

  // ----- effects -----

  delay: Module.make({ input: () => scalar(0), t: () => scalar(0.25) }, params =>
    effects.delay(params.input, params.t)
  ),

  // ----- other helpers -----

  beats: Module.make({ input: () => scalar(0.25) }, params => {
    const n = params.input;
    return Signal.new(synth => (60 / synth.params[P_TEMPO]) * n.value);
  }),

  // TODO: change to sampleAndHold(s: Signal, clock: Signal), trigger on upward zero-crossing
  // (in the arp 2600, the noise generator is hard-wired as the input by default)

  latch: Module.make({ input: () => scalar(0), useLastValue: () => scalar(0) }, params => {
    const { input, useLastValue } = params;
    let lastValue = 0;
    return Signal.new(() => {
      if (useLastValue.value === 0) {
        lastValue = input.value;
      }
      return lastValue;
    });
  }),

  // DC blocking filter: high-pass at ~35Hz to remove DC while preserving audible content
  // Uses a one-pole high-pass: y[n] = x[n] - x[n-1] + α * y[n-1]
  dcBlock: Module.make({ input: () => scalar(0) }, params => {
    const { input } = params;
    // α = 0.995 gives ~35Hz cutoff at 48kHz
    const alpha = 0.995;
    let prevX = 0;
    let prevY = 0;
    return Signal.new(() => {
      const x = input.value;
      const y = x - prevX + alpha * prevY;
      prevX = x;
      prevY = y;
      return y;
    });
  }),

  // https://schaumont.dyn.wpi.edu/ece4703b22/lab5x.html
  pitchShift: Module.make({ input: () => scalar(0), readSpeed: () => scalar(1) }, params => {
    const buffer = new Float32Array(SAMPLE_RATE / 60);
    let writePos = 0;
    let readPos = 0;

    return Signal.new(() => {
      const input = params.input.value;
      const readSpeed = params.readSpeed.value;

      buffer[writePos++] = input;
      if (writePos >= buffer.length) {
        writePos = 0;
      }

      const s1 = interpolatedRead(buffer, readPos);
      const s2 = interpolatedRead(buffer, (readPos + buffer.length / 2) % buffer.length);
      let dist = Math.abs(readPos - writePos);
      if (dist > buffer.length / 2) {
        dist = buffer.length - dist;
      }
      const f = dist / (buffer.length / 2);
      const sample = f * s1 + (1 - f) * s2;

      readPos += readSpeed;
      if (readPos >= buffer.length) {
        readPos = 0;
      }

      return sample;
    });
  }),

  semitones: Module.make({ input: () => scalar(0) }, params =>
    Signal.new(() => Math.pow(2, params.input.value / 12))
  ),
};

// https://mitxela.com/projects/bleps_via_state_machine
function polyBlep(t: number, dt: number) {
  // 0 <= t < 1
  if (t < dt) {
    t /= dt;
    // 2 * (t - t^2/2 - 0.5)
    return t + t - t * t - 1;
  }

  // -1 < t < 0
  if (t > 1 - dt) {
    t = (t - 1) / dt;
    // 2 * (t^2/2 + t + 0.5)
    return t * t + t + t + 1;
  }

  // 0 otherwise
  return 0;
}

(globalThis as any).msynthLib = msynthLib;
