const NUM_VOICES = 6;

// ----- interface w/ worklet -----

let numMidiNotesOn = 0;
const midiNoteVoices = new Map<number, Voice>();

class Voice {
  readonly params = new Float32Array(new SharedArrayBuffer(128 * 4));
  readonly samplerStates = new Float32Array(new SharedArrayBuffer(128 * 4));

  constructor(
    readonly synth: Synth,
    readonly channel: number
  ) {}

  note = -1;

  noteOn(note: number, velocity: number) {
    if (this.isOn) {
      this.noteOff(this.note, 127);
    }
    this.note = note;
    this.synth.sendToVoiceWorklet({
      command: 'process midi message',
      data: midi.noteOn(this.channel, note, velocity),
    });
  }

  noteOff(note: number, velocity: number) {
    this.note = -1;
    this.synth.sendToVoiceWorklet({
      command: 'process midi message',
      data: midi.noteOff(this.channel, note, velocity),
    });
  }

  get isOn() {
    return this.note !== -1;
  }

  get freq() {
    return toFrequency(this.note) * Math.pow(2, this.params[P_GLIDE] / 12);
  }
}

class Synth {
  patch: Patch;
  mode: Mode = 'mpe';
  samples: Float32Array<any> = new Float32Array(new SharedArrayBuffer(5 * 60 * SAMPLE_RATE * 4)); // 5 minutes of samples
  numSamples = 0;
  voiceWorklet: AudioWorkletNode | null = null;
  effectsWorklet: AudioWorkletNode | null = null;
  voices: Voice[] = [];
  octave = 0;
  analyzer: AnalyserNode | null = null;
  timeDomainData: Float32Array<any> | null = null;

  constructor(
    patch: Patch,
    readonly color: string
  ) {
    this.patch = patch;
    for (let ch = 0; ch < NUM_VOICES; ch++) {
      this.voices.push(new Voice(this, ch));
    }
  }

  private _sampler: Sampler | null = null;
  get sampler() {
    return this._sampler ?? (this._sampler = new Sampler(this));
  }

  private _seq: Sequencer | null = null;
  get seq() {
    return this._seq ?? (this._seq = new Sequencer(this));
  }

  private _arp: Arpeggiator | null = null;
  get arp() {
    return this._arp ?? (this._arp = new Arpeggiator(this));
  }

  init() {
    this.voiceWorklet = new AudioWorkletNode(context, 'msynth');
    this.voiceWorklet.channelInterpretation = 'discrete';
    this.voiceWorklet.channelCount = 2;
    this.voiceWorklet.channelCountMode = 'explicit';
    this.sendToVoiceWorklet({
      command: 'init',
      voiceParams: this.voices.map(voice => voice.params.buffer),
      voiceSamplerStates: this.voices.map(voice => voice.samplerStates.buffer),
      samples: this.samples.buffer,
    });
    this.voiceWorklet.port.onmessage = msg =>
      this.onMessageFromWorklet(msg.data as MessageFromSynthWorklet);

    this.effectsWorklet = new AudioWorkletNode(context, 'msynth');
    this.effectsWorklet.channelInterpretation = 'discrete';
    this.effectsWorklet.channelCount = 2;
    this.effectsWorklet.channelCountMode = 'explicit';
    this.sendToEffectsWorklet({
      command: 'init',
      voiceParams: [this.voices[0].params.buffer],
      voiceSamplerStates: [this.voices[0].samplerStates.buffer],
      samples: this.samples.buffer,
    });
    this.effectsWorklet.port.onmessage = msg =>
      this.onMessageFromWorklet(msg.data as MessageFromSynthWorklet);

    this.loadAiModules();

    this.analyzer = context.createAnalyser();
    // Keep buffer short so the scope shows recent audio (~43ms at 48 kHz)
    this.analyzer.fftSize = 2048;
    this.timeDomainData = new Float32Array(this.analyzer.fftSize);

    this.voiceWorklet.connect(this.effectsWorklet).connect(this.analyzer).connect(masterCompressor);
    registerInputConsumer(this.voiceWorklet);

    this.loadPatch(this.patch);
  }

  sendToVoiceWorklet(message: MessageToSynthWorklet) {
    this.voiceWorklet?.port.postMessage(message);
  }

  sendToEffectsWorklet(message: MessageToSynthWorklet) {
    this.effectsWorklet?.port.postMessage(message);
  }

  onMessageFromWorklet(msg: MessageFromSynthWorklet) {
    if (msg.event.startsWith('sequencer:')) {
      this.seq.onMessageFromWorklet(msg);
      return;
    }

    switch (msg.event) {
      case 'sampler: num samples': {
        this.numSamples = msg.value;
        break;
      }
      case 'log': {
        showStatus(msg.message);
        break;
      }
      default: {
        showStatus('??? ' + JSON.stringify(msg));
      }
    }
  }

  getTimeDomainData(): Float32Array | null {
    if (!this.analyzer || !this.timeDomainData) {
      return null;
    }

    this.analyzer.getFloatTimeDomainData(this.timeDomainData);
    return this.timeDomainData;
  }

  loadAiModules() {
    this.sendToVoiceWorklet({
      command: 'load ai modules',
      modules: getAiModulesCode(),
    });
    this.sendToEffectsWorklet({
      command: 'load ai modules',
      modules: getAiModulesCode(),
    });
  }

  loadPatch(patch: Patch, loadInEditor = true) {
    this.patch = patch;
    this.sendToVoiceWorklet({
      command: 'load patch',
      code: patch.voiceCode,
      mono: patch.settings.mono,
    });
    this.sendToEffectsWorklet({
      command: 'load patch',
      code: patch.effectsCode,
      mono: patch.settings.mono,
    });

    // TODO: consider moving this to the worklet
    // (these settings are part of the patch anyway)
    this.setParam(P_GAIN, patch.settings.gain);
    this.setParam(P_TEMPO, tempoWidget.value);
    this.setParam(P_PARAM_A, patch.settings.A);
    this.setParam(P_PARAM_B, patch.settings.B);
    this.setParam(P_PARAM_C, patch.settings.C);
    this.setParam(P_PARAM_D, patch.settings.D);
    this.setParam(P_PARAM_E, patch.settings.E);
    this.setParam(P_PARAM_F, patch.settings.F);
    this.setParam(P_PARAM_G, patch.settings.G);
    this.setParam(P_PARAM_H, patch.settings.H);
    this.octave = patch.settings.octave;
    this.mode = patch.settings.mode;

    if (activeSynth === this && loadInEditor) {
      this.loadPatchInEditor();
    }

    for (const pad of pads) {
      pad.isBeingPlayedBySequencer = false;
    }
  }

  loadPatchInEditor() {
    editor.setPatch(this.patch);
  }

  savePatchCode(part: PatchPart, paramsToo: boolean, showErrors: (errors: CompilerErrors) => void) {
    try {
      const code = editor.view.state.doc.toString();
      compile(code, getAiModules()); // will throw if there's an error
      if (part === 'voice') {
        this.patch.voiceCode = code;
      } else {
        this.patch.effectsCode = code;
      }
      if (paramsToo) {
        this.saveParams();
      }
      this.loadPatch(this.patch, false);
    } catch (e) {
      if (e instanceof CompilerErrors) {
        showErrors(e);
      } else {
        console.error('error saving patch', e);
      }
    }
  }

  saveParams() {
    this.patch.settings = {
      gain: this.getParam(P_GAIN),
      A: this.getParam(P_PARAM_A),
      B: this.getParam(P_PARAM_B),
      C: this.getParam(P_PARAM_C),
      D: this.getParam(P_PARAM_D),
      E: this.getParam(P_PARAM_E),
      F: this.getParam(P_PARAM_F),
      G: this.getParam(P_PARAM_G),
      H: this.getParam(P_PARAM_H),
      octave: this.octave,
      mode: this.mode,
      triggerPeriod: this.seq.state.triggerPeriod,
      noteDuration: this.seq.state.noteDuration,
      // TODO: some way to set these in the UI
      mono: this.patch.settings.mono,
      tempo: this.patch.settings.tempo,
    };
  }

  grabVoice() {
    if (this.patch.settings.mono) {
      return this.voices.find(v => v.channel === 0)!;
    }

    const fingers = [...fingersById.values()];
    const midiVoices = new Set(midiNoteVoices.values());
    const freeVoice = this.voices.findLast(
      v => !fingers.some(f => f.voice === v) && !midiVoices.has(v)
    );
    const voice = freeVoice ?? this.voices.at(-1)!; // if there's no free voice, steal the least recently claimed
    this.voices.splice(this.voices.indexOf(voice), 1);
    this.voices.unshift(voice);
    return voice;
  }

  setParam(n: number, value: number) {
    for (const voice of this.voices) {
      voice.params[n] = value;
    }
  }

  getParam(n: number) {
    return this.voices[0]?.params[n] ?? 0;
  }

  lnf = 220;

  getLowestNoteFreq() {
    let lnf = Infinity;
    for (const voice of this.voices) {
      if (voice.isOn && voice.freq < lnf) {
        lnf = voice.freq;
      }
    }
    if (Number.isFinite(lnf)) {
      this.lnf = lnf;
    }
    return this.lnf;
  }

  panic() {
    for (const voice of this.voices) {
      voice.noteOff(voice.note, 127);
    }
  }
}

