const fingersById = new Map<number, Finger>();

abstract class Finger {
  static isFinger(id: number) {
    return fingersById.has(id);
  }

  static add(id: number, x0: number, y0: number, pressure: number, _synth = activeSynth) {
    switch (_synth.mode) {
      case 'piano':
        return new PianoFinger(id, x0, y0, pressure, _synth);
      case 'mpe':
        return new MpeFinger(id, x0, y0, pressure, _synth);
      case 'string':
        return new StringFinger(id, x0, y0, pressure, _synth);
      case 'strum': {
        const pad = pads.find(pad => pad.contains(x0, y0));
        return pad && pad.col >= ui.LEFTMOST_STRUM_COL
          ? new PickFinger(id, x0, y0, pressure, _synth)
          : new FretFinger(id, x0, y0, pressure, _synth);
      }
      default:
        throw new Error('unknown mode! ' + _synth.mode);
    }
  }

  static updateQuantizationOffsets() {
    for (const finger of fingersById.values()) {
      if (finger instanceof MpeFinger || finger instanceof StringFinger) {
        finger.updateQuantizationOffset();
      }
    }
  }

  x: number;
  y: number;
  quantizationOffset = 0;
  voice: Voice | null = null;
  pad: Pad | null = null;
  readonly speedTracker = new SpeedTracker();

  constructor(
    readonly id: number,
    readonly x0: number,
    readonly y0: number,
    readonly pressure: number,
    readonly synth: Synth
  ) {
    this.x = x0;
    this.y = y0;
    fingersById.set(id, this);
    this.move(x0, y0, pressure);
  }

  abstract move(x: number, y: number, pressure: number): void;
  abstract lift(): void;
  abstract render(): void;

  lastT = performance.now();

  updateQuantizationOffset() {
    const pad = pads.find(p => p.row === this.pad?.row && p.contains(this.x, this.y));

    if (this.speedTracker.speed > 0.025 || !this.pad || !pad) {
      this.lastT = performance.now();
      return;
    }

    const now = performance.now();
    const dt = now - this.lastT;

    const adjustmentSpeed = 0.005; // used to be 0.002
    const f = adjustmentSpeed * dt;
    const wantedQuantizationOffset = (pad.centerX - this.x) / padWidth;
    this.quantizationOffset = f * wantedQuantizationOffset + (1 - f) * this.quantizationOffset;
    this.updateGlide();

    this.lastT = now;
  }

  updateGlide() {
    const newValue = (this.x - this.pad!.centerX) / padWidth + this.quantizationOffset;
    this.voice!.params[P_GLIDE] = newValue;
  }
}

class PianoFinger extends Finger {
  move(x: number, y: number, pressure: number) {
    const newPad = pads.find(pad => pad.contains(x, y)) ?? this.pad;
    const changedPads = newPad !== this.pad;

    if (this.pad && changedPads) {
      this.voice!.noteOff(this.pad.note, 127);
      this.voice = null;
    }

    if (newPad && changedPads) {
      this.voice = this.synth.grabVoice();
    }

    this.pad = newPad;

    if (this.pad) {
      this.voice!.params[P_GLIDE] = 0;
      // TODO: add a setting that sets the slide value relative to where the finger first went down on the pad,
      // this.voice!.params[P_SLIDE] = clamp((this.y0 - y) / (padHeight / 2), -1, 1);
      this.voice!.params[P_SLIDE] = clamp((this.pad.centerY - y) / (padHeight / 2), -1, 1);
      this.voice!.params[P_PRESSURE] = pressure;
      if (changedPads) {
        this.voice!.noteOn(this.pad.note, 127);
        tapeTool.triggerRecordingIfRecIsDown();
      }
    }
  }

  lift() {
    this.voice?.noteOff(this.pad!.note, 127);
  }

  render() {
    renderMpeFinger(this.pad, this.voice);
  }
}

class MpeFinger extends Finger {
  move(x: number, y: number, pressure: number) {
    this.x = x;
    this.y = y;
    this.speedTracker.addPos(x);

    const newPad = pads.find(pad => pad.row !== this.pad?.row && pad.contains(x, y)) ?? this.pad;
    const changedPads = newPad !== this.pad;

    if (this.pad && changedPads) {
      this.voice!.noteOff(this.pad.note, 127);
      this.voice = null;
    }

    if (newPad && changedPads) {
      this.voice = this.synth.grabVoice();
      this.quantizationOffset = (newPad.centerX - x) / padWidth;
    }

    this.pad = newPad;

    if (this.pad) {
      this.updateGlide();
      this.voice!.params[P_SLIDE] = clamp((this.pad.centerY - y) / (padHeight / 2), -1, 1);
      this.voice!.params[P_PRESSURE] = pressure;
      if (changedPads) {
        this.voice!.noteOn(this.pad.note, 127);
        tapeTool.triggerRecordingIfRecIsDown();
      }
    }
  }

  lift() {
    this.voice?.noteOff(this.pad!.note, 127);
  }

  render() {
    renderMpeFinger(this.pad, this.voice);
  }
}

class StringFinger extends Finger {
  pressure = 0;

  move(x: number, y: number, pressure: number) {
    this.x = x;
    this.y = y;
    this.pressure = pressure;
    this.speedTracker.addPos(x);

    const newPad = pads.find(pad => pad.row !== this.pad?.row && pad.contains(x, y));
    const firstInRow = newPad ? firstPadIn(newPad.row) : this.pad;
    const changedPads = firstInRow !== this.pad;

    if (this.pad && changedPads) {
      const row = this.pad.row;
      this.pad = null;
      this.updateRow(row); // this will do a note off if appropriate
      this.voice = null;
    }

    if (firstInRow && changedPads) {
      this.voice = voiceForPadRow(this.synth, firstInRow.row);
      this.quantizationOffset = (newPad!.centerX - x) / padWidth;
    }

    this.pad = firstInRow;

    if (this.pad) {
      this.updateRow(this.pad.row);
    }
  }

  updateRow(row: number) {
    const voice = voiceForPadRow(this.synth, row);
    const pad = firstPadIn(row);
    const highestFinger: StringFinger | null = this.getHighestFinger(row);
    if (highestFinger) {
      highestFinger.updateParams();
      if (!voice.isOn) {
        voice.noteOn(pad.note, 127);
        tapeTool.triggerRecordingIfRecIsDown();
      }
    } else {
      voice.noteOff(pad.note, 127);
    }
  }

  getHighestFinger(row: number) {
    let highest: StringFinger | null = null;
    for (const f of fingersById.values()) {
      if (!(f instanceof StringFinger) || f.pad?.row !== row) {
        continue;
      }
      if (!highest || f.x > highest.x) {
        highest = f;
      }
    }
    return highest;
  }

  updateParams() {
    if (!this.pad || !this.voice) {
      throw new Error('invariant violated!!!');
    }
    if (this !== this.getHighestFinger(this.pad.row)) {
      return;
    }
    this.updateGlide();
    this.voice!.params[P_SLIDE] = clamp((this.pad.centerY - this.y) / (padHeight / 2), -1, 1);
    this.voice!.params[P_PRESSURE] = this.pressure;
  }

  updateGlide() {
    if (this.pad && this === this.getHighestFinger(this.pad.row)) {
      super.updateGlide();
    }
  }

  lift() {
    if (this.pad) {
      this.updateRow(this.pad.row);
    }
  }

  render() {
    renderMpeFinger(this.pad, this.voice);
  }
}

function firstPadIn(row: number) {
  return pads.find(pad => pad.row === row && pad.col === 0)!;
}

const ENABLE_STRUM_BEND = true;
const STRUM_BEND_FACTOR = 0.5;

class FretFinger extends Finger {
  pressure = 0;

  move(x: number, y: number, pressure: number) {
    if (!this.pad) {
      this.pad = pads.find(pad => pad.col < 12 && pad.contains(x, y)) ?? null;
    }

    this.x = x;
    this.y = y;
    this.pressure = pressure;
    this.updateGlide();
  }

  updateGlide() {
    if (this.pad) {
      const highestFinger = this.getHighestFinger(this.pad.row)!;
      highestFinger?._updateGlide();
    }
  }

  _updateGlide() {
    const { row } = this.pad!;
    const soundingPad = firstPadIn(row);
    const bend = ENABLE_STRUM_BEND
      ? (Math.abs(this.y - this.y0) / padHeight) * STRUM_BEND_FACTOR
      : 0;
    const voice = voiceForPadRow(this.synth, row);
    const nearestFret = this.getNearestFret();
    voice.params[P_GLIDE] = nearestFret.note + bend - soundingPad.note;
  }

  getHighestFinger(row: number) {
    let highest: FretFinger | null = null;
    for (const f of fingersById.values()) {
      if (!(f instanceof FretFinger) || f.pad?.row !== row) {
        continue;
      }
      if (!highest || f.x > highest.x) {
        highest = f;
      }
    }
    return highest;
  }

  getNearestFret() {
    let nearestFret = this.pad!;
    let nearestPadDist = Math.abs(nearestFret.centerX - this.x);
    for (const pad of pads) {
      if (pad.row !== this.pad!.row || pad.col >= ui.LEFTMOST_STRUM_COL) {
        continue;
      }
      const d = Math.abs(pad.centerX - this.x);
      if (d < nearestPadDist) {
        nearestFret = pad;
        nearestPadDist = d;
      }
    }
    return nearestFret;
  }

  lift() {
    this.updateGlide();
    if (this.pad && !this.getHighestFinger(this.pad.row)) {
      const voice = voiceForPadRow(this.synth, this.pad.row);
      const soundingPad = firstPadIn(this.pad.row);
      voice.noteOff(soundingPad.note, 127);
    }
  }

  render() {
    if (!this.pad) {
      return;
    }

    const myPad = this.getNearestFret();
    const myX = myPad.centerX;
    const myY = this.y - this.y0 + myPad.centerY;

    ctx.save();
    const color = activeSynth.color;
    ctx.globalAlpha = 0.5;
    ctx.fillStyle = color;
    ctx.beginPath();
    ctx.arc(myX, myY, padWidth / 3, 0, Math.PI * 2);
    ctx.fill();

    for (let pad of pads) {
      if (pad.col !== 0 || pad.row === myPad.row) {
        continue;
      }

      const col = myPad.note - pad.note;
      if (col < 0 || col >= ui.LEFTMOST_STRUM_COL) {
        continue;
      }

      const x = pad.centerX + col * padWidth;
      const y = myY + pad.y - myPad.y;
      ctx.beginPath();
      ctx.lineWidth = 4;
      ctx.strokeStyle = color;
      ctx.arc(x, y, padWidth / 3, 0, Math.PI * 2);
      ctx.stroke();
    }
    ctx.restore();
  }
}

class PickFinger extends Finger {
  // TODO: b/c move() gets called in superclass's constructor, these initializations don't get done
  // until after the 1st call to move()
  velocity = 1;
  maxVelocity = 0;
  prev?: { t: number; y: number };

  move(x: number, y: number, pressure: number) {
    const t = performance.now();
    const numStrumCols = NUM_COLS - ui.LEFTMOST_STRUM_COL;
    this.x = innerWidth - (numStrumCols * padWidth) / 2;
    this.y = y;

    // update velocity
    if (this.prev === undefined) {
      this.prev = { t: performance.now(), y };
      this.velocity = this.maxVelocity = 0.5;
    } else {
      this.velocity = Math.min((15 * Math.abs(y - this.prev.y)) / (t - this.prev.t) / padHeight, 1);
    }
    this.maxVelocity = Math.max(this.velocity, this.maxVelocity);
    // status = `${this.velocity.toFixed(4)} / ${this.maxVelocity.toFixed(4)}`;
    this.prev.t = t;
    this.prev.y = y;

    const oldPad = this.pad;
    this.pad = pads.find(pad => pad.col === 12 && pad.contains(this.x, this.y)) ?? null;
    const changedPads = this.pad !== oldPad;
    if (!changedPads || !this.pad) {
      return;
    }

    const { row, note } = firstPadIn(this.pad.row);
    const voice = voiceForPadRow(activeSynth, row);
    const f = [...fingersById.values()].find(f => f instanceof FretFinger && f.pad?.row === row);
    if (f) {
      (f as FretFinger).updateGlide();
      voice.noteOn(note, 127 * this.velocity);
      tapeTool.triggerRecordingIfRecIsDown();
    }
  }

  lift() {
    // no op
  }

  render() {
    ctx.beginPath();
    ctx.fillStyle = activeSynth.color;
    ctx.arc(this.x, this.y, padWidth / 3, 0, Math.PI * 2);
    ctx.fill();
  }
}

function renderMpeFinger(fingerPad: Pad | null, voice: Voice | null) {
  if (!fingerPad || !voice) {
    return;
  }

  for (let pad of pads) {
    if (pad.col !== 0) {
      continue;
    }

    const x = pad.centerX + (fingerPad.note - pad.note + voice.params[P_GLIDE]) * padWidth;
    const y = pad.centerY - voice.params[P_SLIDE] * (padHeight / 2);
    const p = voice.params[P_PRESSURE] * 0.5 + 0.5; // scale pressure to 0.5..1.0
    const color = activeSynth.color;
    ctx.save();
    ctx.globalAlpha = p;

    const shouldFill = pad.row === fingerPad.row;
    if (shouldFill) {
      ctx.beginPath();
      ctx.arc(x, y, padWidth / 4, 0, Math.PI * 2);
      ctx.fillStyle = color;
      ctx.fill();
    }

    for (let idx = 0; idx < 4; idx++) {
      ctx.beginPath();
      ctx.strokeStyle = color;
      ctx.lineCap = 'round';
      ctx.lineWidth = 4;
      const offset = (performance.now() / 2000 + idx / 4) * TAU;
      ctx.arc(x, y, padWidth / 3, offset, offset + TAU / 8);
      ctx.stroke();
    }
    ctx.restore();
  }
}

