class Scope extends Display {
  constructor(options: ThingOptions) {
    super(options);
  }

  renderDisplay() {
    const data = activeSynth.getTimeDomainData();
    if (!data) {
      return;
    }

    const freq = activeSynth.getLowestNoteFreq();
    const samplesPerCycle = SAMPLE_RATE / freq;
    const cyclesToDisplay = 2;
    const requiredSamples = Math.round(samplesPerCycle * cyclesToDisplay);

    // Find the first upward zero-crossing point
    let triggerIndex = 0;
    for (let i = 0; i < data.length - 1; i++) {
      if (data[i] <= 0 && data[i + 1] > 0) {
        triggerIndex = i;
        break; // Found our starting point
      }
    }

    ctx.beginPath();

    const end = Math.min(triggerIndex + requiredSamples, data.length);
    const numSamplesToShow = Math.max(1, end - triggerIndex);
    const sliceWidth = this.displayW / numSamplesToShow;
    let x = this.displayX;
    let y = 0;

    const SCOPE_HEADROOM = 0.7;
    let peak = 0;
    for (let i = triggerIndex; i < end; i++) {
      peak = Math.max(peak, Math.abs(data[i]));
    }
    const scale = SCOPE_HEADROOM / Math.max(peak, 1e-6);

    const halfH = this.displayH / 2;
    const midY = this.displayY + halfH;

    for (let i = triggerIndex; i < end; i++) {
      y = midY - data[i] * halfH * scale;
      if (i === triggerIndex) {
        ctx.moveTo(x, y);
      } else {
        ctx.lineTo(x, y);
      }
      x += sliceWidth;
    }

    // Patches/effects rarely hit unity before gain; comparing peak to raw `gain`
    // makes the trace nearly invisible at moderate faders. Full opacity when peak
    // reaches this fraction of the gain-limited ceiling (still caps at 1 when peak ≥ gain).
    const SCOPE_OPACITY_FULL_AT_GAIN_FRAC = 0.22;
    const SCOPE_TRACE_MIN_ALPHA = 0.18;
    const gain = activeSynth.getParam(P_GAIN);
    const refLevel = Math.max(gain * SCOPE_OPACITY_FULL_AT_GAIN_FRAC, 1e-6);
    const loudness = Math.min(peak / refLevel, 1);
    const traceAlpha = SCOPE_TRACE_MIN_ALPHA + (1 - SCOPE_TRACE_MIN_ALPHA) * loudness;

    ctx.save();
    ctx.globalAlpha = traceAlpha;
    ctx.lineWidth = 2;
    ctx.strokeStyle = ui.OSCILLOSCOPE_TRACE_COLOR;
    ctx.stroke();
    ctx.restore();
  }
}

class Sequencer extends Column {
  state: SequencerState = {
    patternA: { notes: [] },
    patternB: { notes: [] },
    currPattern: 'A',
    currStep: 0,
    nextPattern: 'A',
    triggerPeriod: 1 / 8,
    noteDuration: 0.5,
    swing: 0.5,
    playing: false,
    recordingRhythmStepIdx: null,
  };
  private recording = false;

  constructor(readonly synth: Synth) {
    super({ w: () => padWidth * 5 });
    const seq = this;
    this.addChild(
      new (class extends Display {
        constructor() {
          super({ h: () => padHeight * 2 });
        }

        rhythmFingerDownId: number | null = null;

        onPointerDown(x: number, y: number, e: PointerEvent) {
          if (seq.state.recordingRhythmStepIdx !== null) {
            if (this.rhythmFingerDownId !== null) {
              seq.synth.sendToVoiceWorklet({
                command: 'sequencer rhythm: finger up',
              });
            }
            seq.synth.sendToVoiceWorklet({
              command: 'sequencer rhythm: finger down',
            });
            this.rhythmFingerDownId = e.pointerId;
          } else if (x < this.x + padWidth) {
            seq.setCurrPattern(seq.state.currPattern === 'A' ? 'B' : 'A');
          } else if (x > this.rightX - padWidth) {
            seq.setNextPattern(shift() ? '●' : seq.state.nextPattern === 'A' ? 'B' : 'A');
          } else {
            if (seq.recording) {
              // add rest
              seq.setPatternSteps({ notes: [...seq.pattern.notes, []] });
            } else if (seq.state.playing) {
              seq.stop();
            } else {
              seq.start();
            }
          }
          return true;
        }

        onPointerUp(x: number, y: number, e: PointerEvent) {
          if (
            seq.state.recordingRhythmStepIdx !== null &&
            this.rhythmFingerDownId === e.pointerId
          ) {
            seq.synth.sendToVoiceWorklet({
              command: 'sequencer rhythm: finger up',
            });
            this.rhythmFingerDownId = null;
          }
        }

        override renderDisplay() {
          ctx.font = ui.Font.buttonHuge.cssFontString;
          ctx.fillStyle = '#fff';
          ctx.textAlign = 'center';
          ctx.textBaseline = 'middle';
          ctx.fillText(
            seq.state.currPattern,
            this.x + padWidth / 2,
            this.displayY + this.displayH / 2
          );
          ctx.fillText(
            seq.state.nextPattern,
            this.rightX - padWidth / 2,
            this.displayY + this.displayH / 2
          );
          ctx.fillStyle = '#ccc';
          ctx.font = ui.Font.buttonBig.cssFontString;
          ctx.fillText('→', this.rightX - (3 * padWidth) / 2, this.displayY + this.displayH / 2);
          ctx.fillStyle = seq.synth.color;
          const numSteps = Math.max(seq.pattern.notes.length, 32);
          const numCols = 8;
          const numRows = Math.ceil(numSteps / numCols);
          const gridSize = (2 * padWidth) / numCols;
          const r = gridSize * 0.25;
          const left = this.x + padWidth + 0.5 * gridSize;
          let x = left;
          let y = this.centerY + ((1 - numRows) * gridSize) / 2;
          for (let i = 0; i < numSteps; i++) {
            if (i > 0 && i % numCols === 0) {
              x = left;
              y += gridSize;
            }
            const isActualStep = i < seq.pattern.notes.length;
            const isRest = isActualStep && seq.pattern.notes[i].length === 0;
            const isCurrentStep = seq.state.currStep === i;
            ctx.globalAlpha = isActualStep ? 1 : 0.25;
            ctx.beginPath();
            ctx.arc(x, y, r, 0, 2 * Math.PI);
            if (!isRest) {
              ctx.fillStyle = seq.synth.color;
              ctx.fill();
            }
            ctx.lineWidth = 2;
            ctx.strokeStyle = isCurrentStep ? '#fff' : seq.synth.color;
            ctx.stroke();
            if (i === seq.state.recordingRhythmStepIdx) {
              ctx.strokeStyle = 'yellow';
              ctx.beginPath();
              ctx.roundRect(
                x - gridSize / 2,
                y - gridSize / 2,
                gridSize,
                gridSize,
                ui.RECTANGLE_RADIUS
              );
              ctx.stroke();
            }
            x += gridSize;
          }
        }
      })()
        .addChild(
          new EmbeddedSelector({
            values: [1 / 4, 1 / 8, 1 / 16, 1 / 32],
            getValue: () => this.state.triggerPeriod,
            setValue(value) {
              synth.sendToVoiceWorklet({
                command: 'sequencer: set trigger period',
                value,
              });
            },
            valueToString(value) {
              if (value === 1 / 4) {
                return 'div 1/4';
              } else if (value === 1 / 8) {
                return 'div 1/8';
              } else if (value === 1 / 16) {
                return 'div 1/16';
              } else if (value === 1 / 32) {
                return 'div 1/32';
              }
            },
          }),
          'top left'
        )
        .addChild(
          Label.new({
            color: () => seq.synth.color,
            label: () => 'seq',
            border: true,
          }),
          'top right'
        )
        .addChild(
          Label.new({
            color: () => '#ff3333',
            border: true,
            label: () => 'record',
            onPointerDown() {
              if (shift()) {
                if (seq.state.recordingRhythmStepIdx === null) {
                  seq.synth.sendToVoiceWorklet({
                    command: 'sequencer rhythm: start recording',
                  });
                } else {
                  seq.synth.sendToVoiceWorklet({
                    command: 'sequencer rhythm: cancel recording',
                  });
                }
              } else {
                seq.startRecording();
              }
            },
            onPointerUp() {
              if (seq.state.recordingRhythmStepIdx == null) {
                seq.stopRecording();
              }
            },
          }),
          'top center'
        )
        .addChild(
          new EmbeddedSelector({
            values: [0.1, 0.25, 0.5, 0.75, 0.9],
            getValue: () => this.state.noteDuration,
            setValue: value =>
              synth.sendToVoiceWorklet({
                command: 'sequencer: set note duration',
                value,
              }),
            valueToString: value => `gate ${(value * 100).toFixed(0)}%`,
          }),
          'bottom left'
        )
        .addChild(
          new EmbeddedSelector({
            values: [0.5, 0.52, 0.54, 0.57, 0.6, 0.63, 0.67, 0.71, 0.75],
            getValue: () => this.state.swing,
            setValue(value) {
              synth.sendToVoiceWorklet({ command: 'sequencer: set swing', value });
            },
            valueToString(value) {
              return value === 0.5 ? 'swing off' : 'swing ' + (value * 100).toFixed(0) + '%';
            },
          }),
          'bottom right'
        )
    );
  }

  private get isActive() {
    return activeTool === this || (activeTool === activeSynthSeq && activeSynth === this.synth);
  }

  private get otherSeq() {
    return this === synth1.seq ? synth2.seq : synth1.seq;
  }

  private get pattern() {
    return this.state.currPattern === 'A' ? this.state.patternA : this.state.patternB;
  }

  start(pattern?: PatternName) {
    if (this.pattern.notes.length === 0) {
      return;
    }

    if (pattern) {
      this.setCurrPattern(pattern);
    }
    this.synth.setParam(P_GLIDE, 0);
    this.synth.sendToVoiceWorklet({ command: 'sequencer: start' });

    if (this.isActive) {
      if (followActiveSequencer) {
        this.otherSeq.start(this.state.currPattern);
      }
      tapeTool.triggerRecordingIfRecIsDown();
    }
  }

  stop() {
    this.synth.sendToVoiceWorklet({ command: 'sequencer: stop' });
    if (followActiveSequencer && this.isActive) {
      this.otherSeq.stop();
    }
  }

  private resolveOnNewState?: (state: SequencerState) => void;

  async startRecording() {
    this.recording = true;
    await this.setPatternSteps({ notes: [] });
  }

  async setPatternSteps(steps: Pattern) {
    const newState = new Promise(resolve => {
      this.resolveOnNewState = resolve;
    });
    this.synth.sendToVoiceWorklet({
      command: 'sequencer: set pattern steps',
      pattern: this.state.currPattern,
      steps,
    });
    await newState;
  }

  async setCurrPattern(pattern: PatternName) {
    const newState = new Promise(resolve => {
      this.resolveOnNewState = resolve;
    });
    this.synth.sendToVoiceWorklet({
      command: 'sequencer: set curr pattern',
      pattern,
    });
    if (followActiveSequencer && this.isActive) {
      this.otherSeq.synth.sendToVoiceWorklet({
        command: 'sequencer: set curr pattern',
        pattern,
      });
    }
    await newState;
  }

  async setNextPattern(pattern: PatternName | '●') {
    const newState = new Promise(resolve => {
      this.resolveOnNewState = resolve;
    });
    this.synth.sendToVoiceWorklet({
      command: 'sequencer: set next pattern',
      pattern,
    });
    if (followActiveSequencer && this.isActive) {
      this.otherSeq.synth.sendToVoiceWorklet({
        command: 'sequencer: set next pattern',
        pattern,
      });
    }
    await newState;
  }

  stopRecording() {
    this.recording = false;
    this.start();
  }

  async onNotePressed(note: number, isTheOnlyOne: boolean) {
    if (!this.recording) {
      return;
    }

    if (isTheOnlyOne) {
      // this is the first note for this step!
      await this.setPatternSteps({ notes: [...this.pattern.notes, [note]] });
    } else {
      const lastStep = this.pattern.notes.at(-1);
      if (!lastStep) {
        throw new Error('WAT');
      }
      lastStep.push(note);
      await this.setPatternSteps({ notes: this.pattern.notes });
    }
  }

  onMessageFromWorklet(msg: MessageFromSynthWorklet) {
    switch (msg.event) {
      case 'sequencer: state': {
        this.state = msg.state;
        if (this.resolveOnNewState) {
          this.resolveOnNewState(this.state);
          this.resolveOnNewState = undefined;
        }
        break;
      }
      case 'sequencer: step': {
        if (msg.action === 'noteOn') {
          this.state.currStep = msg.index;
        }
        if (this.synth === activeSynth) {
          for (const note of this.pattern.notes[msg.index] ?? []) {
            for (const pad of pads) {
              if (pad.note === note) {
                pad.isBeingPlayedBySequencer = msg.action === 'noteOn';
              }
            }
          }
        }
        break;
      }
      default:
        showStatus('??? ' + JSON.stringify(msg));
    }
  }

  get foregroundColor() {
    return '#fff';
  }
}

