class Sampler extends Display {
  recording = false;
  private waveAmplitudes?: Float32Array;
  private waveSmoothed?: Float32Array;

  constructor(readonly synth: Synth) {
    super({ w: () => padWidth * 4 });
    this.addChild(
      Label.new({
        label: () => 'sampler',
        color: () => activeSynth.color,
        border: true,
      }),
      'top right'
    ).addChild(
      Label.new({
        color: () => '#ff3333',
        border: true,
        label: () => 'record',
        onPointerDown: () => this.startRecording(),
        onPointerUp: () => this.stopRecording(),
      }),
      'top center'
    );
  }

  startRecording() {
    this.synth.sendToVoiceWorklet({ command: 'sampler: start recording' });
    this.recording = true;
  }

  stopRecording() {
    this.synth.sendToVoiceWorklet({ command: 'sampler: stop recording' });
    this.recording = false;
  }

  override renderDisplay() {
    if (this.synth.numSamples === 0) {
      ctx.fillStyle = activeSynth.color;
      ctx.font = ui.Font.buttonBig.cssFontString;
      ctx.textAlign = 'center';
      ctx.textBaseline = 'middle';
      ctx.fillText('no samples', this.x + 2 * padWidth, this.displayY + this.displayH / 2);
      return;
    }

    this.renderSamples();

    const samplerStatesDo = (
      fn: (phase: number, _in: number, out: number, loopIn: number, loopOut: number) => void
    ) => {
      for (const voice of this.synth.voices) {
        const numSamplerStates = voice.samplerStates[0];
        for (let i = 0; i < numSamplerStates; i++) {
          const idx = 1 + i * 5;
          const phase = voice.samplerStates[idx + 0];
          const _in = voice.samplerStates[idx + 1];
          const out = voice.samplerStates[idx + 2];
          const loopIn = voice.samplerStates[idx + 3];
          const loopOut = voice.samplerStates[idx + 4];
          fn(phase, _in, out, loopIn, loopOut);
        }
      }
    };

    const x = (value: number) => this.displayX + value * this.displayW;
    const gray = '#777';

    // draw lines

    samplerStatesDo((phase, _in, out, loopIn, loopOut) => {
      if (_in !== 0 || out !== 1) {
        ctx.fillStyle = this.synth.color;
        ctx.fillRect(x(_in), this.displayY, 1, this.displayH);
        ctx.fillRect(x(out), this.displayY, 1, this.displayH);
      }
      if (loopIn !== 0 || loopOut !== 1) {
        const dir = _in < out ? 1 : -1;
        const loopingMakesSense = dir > 0 ? loopIn < loopOut : loopIn > loopOut;
        ctx.fillStyle = loopingMakesSense ? this.synth.color : gray;
        ctx.fillRect(x(loopIn), this.displayY, 1, this.displayH);
        ctx.fillRect(x(loopOut), this.displayY, 1, this.displayH);
      }
      if (phase > 0) {
        ctx.fillRect(x(phase), this.displayY, 1, this.displayH);
      }
    });

    // draw ranges

    const size = padWidth / 20;
    ctx.fillStyle = gray;

    const drawTriangle = (x: number, pos: 'top' | 'bottom') => {
      const y = pos === 'top' ? this.displayY : this.displayY + this.displayH;
      ctx.beginPath();
      ctx.moveTo(x - size, y);
      ctx.lineTo(x + size, y);
      ctx.lineTo(x + 1, y + (pos === 'top' ? size : -size));
      ctx.lineTo(x - 1, y + (pos === 'top' ? size : -size));
      ctx.closePath();
      ctx.fill();
    };

    samplerStatesDo((phase, _in, out, loopIn, loopOut) => {
      if (_in !== 0 || out !== 1) {
        ctx.fillRect(x(_in), this.displayY + this.displayH, x(out) - x(_in), -size);
        drawTriangle(x(_in), 'bottom');
        drawTriangle(x(out), 'bottom');
      }
      if (loopIn !== 0 || loopOut !== 1) {
        ctx.fillRect(x(loopIn), this.displayY, x(loopOut) - x(loopIn), size);
        drawTriangle(x(loopIn), 'top');
        drawTriangle(x(loopOut), 'top');
      }
    });

    // draw labels

    const labelOffset = 8;
    ctx.textBaseline = 'middle';
    ctx.font = ui.Font.labelSmall.cssFontString;

    const drawLabel = (text: string) => {
      ctx.lineWidth = 2;
      ctx.globalAlpha = 0.5;
      ctx.strokeText(text, 0, 0);
      ctx.globalAlpha = 1;
      ctx.fillText(text, 0, 0);
    };

    samplerStatesDo((phase, _in, out, loopIn, loopOut) => {
      if (_in !== 0 || out !== 1) {
        const labelY = this.displayY + this.displayH - 2.5 * ui.Font.label.sizeInPixels;
        ctx.textAlign = 'left';
        ctx.fillStyle = '#fff';

        ctx.save();
        ctx.translate(x(_in) + (_in <= out ? -1 : 1) * labelOffset, labelY);
        ctx.rotate(-Math.PI / 2);
        drawLabel('in');
        ctx.restore();

        ctx.save();
        ctx.translate(x(out) + (_in <= out ? 1 : -1) * labelOffset, labelY);
        ctx.rotate(-Math.PI / 2);
        drawLabel('out');
        ctx.restore();
      }
      if (loopIn !== 0 || loopOut !== 1) {
        const labelY = this.displayY + 2.5 * ui.Font.label.sizeInPixels;
        ctx.textAlign = 'right';
        ctx.fillStyle = '#fff';

        ctx.save();
        ctx.translate(x(loopIn) + (loopIn <= loopOut ? -1 : 1) * labelOffset, labelY);
        ctx.rotate(-Math.PI / 2);
        drawLabel('↻ in');
        ctx.restore();

        ctx.save();
        ctx.translate(x(loopOut) + (loopIn <= loopOut ? 1 : -1) * labelOffset, labelY);
        ctx.rotate(-Math.PI / 2);
        drawLabel('↻ out');
        ctx.restore();
      }
    });
  }

  renderSamples() {
    let max = -Infinity;
    for (let i = 0; i < this.synth.numSamples; i++) {
      const sample = this.synth.samples[i];
      max = Math.max(max, Math.abs(sample));
    }

    if (!isFinite(max) || max === 0) {
      return;
    }

    ctx.fillStyle = '#fff';

    const numPixels = Math.max(1, Math.ceil(this.displayW));

    if (!this.waveAmplitudes || !this.waveSmoothed || this.waveAmplitudes.length < numPixels) {
      this.waveAmplitudes = new Float32Array(numPixels);
      this.waveSmoothed = new Float32Array(numPixels);
    }

    // First, compute a per-pixel peak amplitude so we preserve detail without jagged bars.
    for (let x = 0; x < numPixels; x++) {
      const start = Math.floor((x / numPixels) * this.synth.numSamples);
      const end = Math.floor(((x + 1) / numPixels) * this.synth.numSamples);
      let v = 0;
      for (let i = start; i < end; i++) {
        const sample = this.synth.samples[i];
        v = Math.max(v, Math.abs(sample));
      }
      this.waveAmplitudes[x] = v / max;
    }

    // Apply a simple smoothing filter to make the silhouette less jagged.
    const radius = 2;
    for (let x = 0; x < numPixels; x++) {
      let sum = 0;
      let count = 0;
      for (let dx = -radius; dx <= radius; dx++) {
        const ix = x + dx;
        if (ix < 0 || ix >= numPixels) continue;
        sum += this.waveAmplitudes[ix];
        count++;
      }
      this.waveSmoothed[x] = count ? sum / count : this.waveAmplitudes[x];
    }

    const halfH = this.displayH / 2;
    const startX = Math.floor(this.displayX);

    ctx.beginPath();

    // Top contour from left to right.
    for (let x = 0; x < numPixels; x++) {
      const amp = this.waveSmoothed[x];
      const canvasX = startX + x;
      const y = this.centerY - amp * halfH;
      if (x === 0) {
        ctx.moveTo(canvasX, this.centerY);
        ctx.lineTo(canvasX, y);
      } else {
        ctx.lineTo(canvasX, y);
      }
    }

    // Bottom contour back from right to left to create a filled shape.
    for (let x = numPixels - 1; x >= 0; x--) {
      const amp = this.waveSmoothed[x];
      const canvasX = startX + x;
      const y = this.centerY + amp * halfH;
      ctx.lineTo(canvasX, y);
    }

    ctx.closePath();
    ctx.fill();
  }
}

let shiftIsPressed = false;

function shift() {
  return msynthButton.isPressed || shiftIsPressed;
}

// Canvas isn't focusable, so key events never fire on it. Use window.
window.addEventListener('keydown', e => {
  if (e.repeat) {
    // ignore
    return;
  }

  switch (e.key) {
    case 'Shift':
      shiftIsPressed = true;
      break;
    case ' ':
      if (activeTool === activeSynthSeq || activeTool === activeSynth.seq) {
        activeSynth.seq.startRecording();
      } else {
        tapeState().playButtonDown = true;
      }
      break;
    case '.':
      tapeState().recButtonDown = true;
      break;
  }
});

window.addEventListener('keyup', e => {
  if (e.repeat) {
    // ignore
    return;
  }

  switch (e.key) {
    case 'Shift':
      shiftIsPressed = false;
      break;
    case ' ':
      if (activeTool === activeSynthSeq || activeTool === activeSynth.seq) {
        activeSynth.seq.stopRecording();
      } else {
        tapeState().playButtonDown = false;
      }
      break;
    case '.':
      tapeState().recButtonDown = false;
      break;
  }
});

