const msynthButton = new (class extends Button {
  constructor() {
    super({
      w: () => padWidth,
      h: () => padHeight * 2,
      label: () => '',
    });
  }

  private numFingersDown = 0;
  private releaseGraceUntilMs = 0;
  private readonly releaseGraceMs = 120;

  panic() {
    this.numFingersDown = 0;
    this.releaseGraceUntilMs = 0;
  }

  get isPressed() {
    return this.numFingersDown > 0 || performance.now() < this.releaseGraceUntilMs;
  }

  get isDoublePressed() {
    return this.numFingersDown === 2;
  }

  onPointerDown() {
    this.numFingersDown++;
    this.releaseGraceUntilMs = 0;
    return true;
  }

  onPointerUp() {
    this.numFingersDown = Math.max(0, this.numFingersDown - 1);
    if (this.numFingersDown === 0) {
      // Touch platforms can briefly emit an "up/cancel" for one finger while another
      // is still intended to be held. Keep shift alive very briefly to avoid
      // reclassifying nearby tape-button touches as note touches.
      this.releaseGraceUntilMs = performance.now() + this.releaseGraceMs;
    }
  }

  render() {
    super.render();

    const x = this.x + this.w / 2;
    const y = this.y + this.h / 2;

    ctx.translate(x, y);
    ctx.rotate(-Math.PI / 2); // rotate -90 degrees for sideways text

    // Choose biggest font size that fits
    let fontSize = Math.floor(this.h * 0.7); // may overshoot due to rotation
    ctx.font = `bold ${fontSize}px Inter`;
    // Shrink font if too wide even after rotation
    const text = 'MSYNTH';
    const maxHeight = this.h * 0.9;
    let textMetrics = ctx.measureText(text);
    if (textMetrics.width > maxHeight) {
      fontSize = Math.floor((maxHeight * fontSize) / textMetrics.width);
      ctx.font = `700 ${fontSize}px Inter`;
      textMetrics = ctx.measureText(text);
    }

    ctx.scale(1, (this.w * 1) / fontSize);
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.fillStyle = activeSynth.color;
    ctx.fillText(text, 0, navigator.userAgent.includes('Chrome') ? 2 : 0);
  }
})();

type TempoSource = 'auto' | 'free' | Synth;
const tempoWidget = new (class extends Thing {
  private source: TempoSource = 'auto';
  private _value = 120;

  constructor() {
    super({
      w: () => padWidth,
      h: () => padHeight * 2,
      hasBackground: true,
    });
    this.addChild(
      new EmbeddedSelector<TempoSource>({
        color: () => '#555',
        values: ['auto', 'free', synth1, synth2],
        getValue: () => this.source,
        setValue: value => {
          this.source = value;
        },
        valueToString: value => {
          if (typeof value === 'string') {
            return value;
          } else if (value === synth1) {
            return 'synth 1';
          } else if (value === synth2) {
            return 'synth 2';
          } else {
            return '???';
          }
        },
      }),
      'bottom center'
    );
  }

  get foregroundColor() {
    return this.source instanceof Synth ? this.source.color : '#000';
  }

  get value() {
    switch (this.source) {
      case 'auto':
        return synth1.patch.settings.tempo ?? synth2.patch.settings.tempo ?? this._value;
      case synth1:
        return synth1.patch.settings.tempo ?? this._value;
      case synth2:
        return synth2.patch.settings.tempo ?? this._value;
      case 'free':
        return this._value;
    }
  }

  private pointerDownY?: number;
  private pointerDownValue?: number;

  onPointerDown(x: number, y: number, e: PointerEvent) {
    this.pointerDownY = y;
    this.pointerDownValue = this.value;
    return true;
  }

  onPointerMove(x: number, y: number, e: PointerEvent) {
    const dy = this.pointerDownY! - y;
    if (this.source !== 'free' && Math.abs(dy) > 5) {
      this._value = this.pointerDownValue = this.value;
      this.source = 'free';
    }
    if (this.source === 'free') {
      this._value = Math.round(clamp(this.pointerDownValue! + dy / 10, 10, 200));
    }
  }

  onPointerUp(x: number, y: number, e: PointerEvent) {
    this.pointerDownY = undefined;
    this.pointerDownValue = undefined;
  }

  render() {
    super.render();
    this.renderLabel(
      'tempo',
      ui.Font.button,
      this.centerX,
      this.centerY - ui.Font.buttonBig.sizeInPixels,
      this.foregroundColor,
      0.7
    );
    this.renderLabel(
      '' + this.value,
      ui.Font.buttonBig,
      this.centerX,
      this.centerY,
      this.foregroundColor,
      1
    );

    synth1.setParam(P_TEMPO, this.value);
    synth2.setParam(P_TEMPO, this.value);
    tapeState().tempo = this.value;
  }
})();

