// Finger creation is handled by the pads themselves, but the handlers below
// are needed for move/lift.

canvas.addEventListener('pointermove', e => {
  const finger = fingersById.get(e.pointerId);
  if (finger) {
    finger.move(e.offsetX, e.offsetY, getPressure(e));
    e.preventDefault();
  }
});

canvas.addEventListener('pointerup', onPointerUp);
canvas.addEventListener('pointercancel', onPointerUp);

function onPointerUp(e: PointerEvent) {
  const finger = fingersById.get(e.pointerId);
  if (finger) {
    fingersById.delete(e.pointerId);
    finger.lift();
  }
  canvas.releasePointerCapture(e.pointerId);
}

function render() {
  ctx.clearRect(0, 0, innerWidth, innerHeight);

  const padsBottomY = (FIRST_ROW + NUM_ROWS) * padHeight;
  const editorClosedTop = padsBottomY - ui.EDITOR_BUTTON_BAR_HEIGHT;
  const editorOpenTop =
    padsBottomY + editorState.rowOffset * padHeight - ui.EDITOR_BUTTON_BAR_HEIGHT;
  const editorHeight = ui.EDITOR_BUTTON_BAR_HEIGHT + ui.EDITOR_HEIGHT_IN_PADS * padHeight;

  editor.container.style.display =
    editorState.editingPatch || editorState.closing ? 'flex' : 'none';
  editor.container.style.height = `${editorHeight}px`;

  if (editorState.closing) {
    if (!editorState.closingTopApplied) {
      editor.container.style.top = `${editorClosedTop}px`;
      editorState.closingTopApplied = true;
    }
    if (!editorState.closingListenerAdded) {
      editorState.closingListenerAdded = true;
      editor.container.addEventListener(
        'transitionend',
        (e: TransitionEvent) => {
          if (e.propertyName !== 'top' || e.target !== editor.container) {
            return;
          }
          finishPatchEditorClose();
        },
        { once: true }
      );
      if (editorState.closeFallbackTimer != null) {
        clearTimeout(editorState.closeFallbackTimer);
      }
      editorState.closeFallbackTimer = setTimeout(finishPatchEditorClose, 400);
    }
  } else if (editorState.editingPatch && editorState.justOpened) {
    editor.container.style.top = `${editorClosedTop}px`;
    editorState.justOpened = false;
  } else if (editorState.editingPatch) {
    editor.container.style.top = `${editorOpenTop}px`;
  }

  topLevelThing.recursiveRender();
  topLevelThing.recursiveRenderOnTop();

  for (const finger of fingersById.values()) {
    finger.render();
  }

  for (const [note, voice] of midiNoteVoices.entries()) {
    const pad = pads.find(pad => pad.note === note);
    if (pad) {
      renderMpeFinger(pad, voice);
    }
  }

  renderStatus();

  Finger.updateQuantizationOffsets();

  requestAnimationFrame(render);
}

render();

// ---- web audio -----

afterWebAudioInitializedDo(() => {
  tapeTool.tape.init();
  synth1.init();
  synth2.init();

  synth1.effectsWorklet!.connect(tapeTool.tape.worklet!);
  synth2.effectsWorklet!.connect(tapeTool.tape.worklet!);
});

// ----- interactions -----

function getPressure(e: PointerEvent) {
  if (e.pointerType === 'pen') {
    return e.pressure;
  } else if (e.pointerType === 'touch') {
    return Math.abs(Math.max(e.width, e.height) - 20) / (150 - 20);
  } else {
    return 1;
  }
}

// ----- external control -----

function noteOn(note: number, velocity: number) {
  ensureWebAudioInitialized();

  numMidiNotesOn++;
  activeSynth.seq.onNotePressed(note, numMidiNotesOn === 1);

  // only play if seq is not playing!
  if (!activeSynth.seq.state.playing) {
    const voice = activeSynth.grabVoice()!;
    midiNoteVoices.set(note, voice);
    voice.params[P_GLIDE] = 0;
    voice.params[P_SLIDE] = 0;
    voice.params[P_PRESSURE] = velocity / 127;
    voice.noteOn(note, velocity);
  }
}

function noteOff(note: number, velocity = 127) {
  midiNoteVoices.get(note)?.noteOff(note, velocity);
  midiNoteVoices.delete(note);
  numMidiNotesOn--;
}

function pitchBend(numSemitones: number) {
  activeSynth.setParam(P_GLIDE, numSemitones);
}

try {
  await setUpMidi(noteOn, noteOff, pitchBend);
} catch (e) {
  console.log('unable to set up midi', e);
}

setUpKeyboard(noteOn, noteOff, pitchBend);
